class Solution:
    def smallestValue(self, n: int) -> int:
        def prime_factors(num):
            i = 2
            factors = []
            while i * i <= num:
                if num % i:
                    i += 1
                else:
                    num //= i
                    factors.append(i)
            if num > 1:
                factors.append(num)
            return factors

        while True:
            factors = prime_factors(n)
            new_n = sum(factors)
            if new_n == n:
                return n
            n = new_n
